# Input validation patterns
ALLOWED_TABLE_NAMES = {'YourTableName', 'AnotherTableName'}
ALLOWED_BUCKET_NAMES = {'your-app-bucket', 'your-data-bucket'}
ALLOWED_QUEUE_NAMES = {'your-queue-name'}
ALLOWED_TOPIC_ARNS = {'arn:aws:sns:us-east-1:123456789012:your-topic-name'}

# Secure input validation
class InputValidator:
    @staticmethod
    def validate_string(value: str, max_length: int = 255, pattern: Optional[str] = None) -> str:
        if not isinstance(value, str):
            raise ValueError("Input must be a string")
        
        if len(value) > max_length:
            raise ValueError(f"Input exceeds maximum length of {max_length}")
        
        if pattern and not re.match(pattern, value):
            raise ValueError("Input does not match required pattern")
        
        return value
    
    @staticmethod
    def validate_table_name(table_name: str) -> str:
        if table_name not in ALLOWED_TABLE_NAMES:
            raise ValueError("Invalid table name")
        return table_name
    
    @staticmethod
    def validate_bucket_name(bucket_name: str) -> str:
        if bucket_name not in ALLOWED_BUCKET_NAMES:
            raise ValueError("Invalid bucket name")
        return bucket_name
    
    @staticmethod
    def sanitize_log_data(data: Any) -> Any:
        """Remove sensitive fields from log data"""
        if isinstance(data, dict):
            sensitive_keys = {'password', 'token', 'secret', 'api_key', 'authorization', 'ssn', 'credit_card'}
            return {k: '***REDACTED***' if k.lower() in sensitive_keys else InputValidator.sanitize_log_data(v) 
                    for k, v in data.items()}
        elif isinstance(data, list):
            return [InputValidator.sanitize_log_data(item) for item in data]
        return data

# Secure AWS service clients
class SecureAWSClients:
    def __init__(self):
        self.s3 = boto3.client('s3')
        self.dynamodb = boto3.resource('dynamodb')
        self.sns = boto3.client('sns')
        self.sqs = boto3.client('sqs')
        self.secrets_manager = boto3.client('secretsmanager')
    
    def get_secret(self, secret_name: str) -> Dict[str, Any]:
        """Securely retrieve secrets from AWS Secrets Manager"""
        try:
            validated_name = InputValidator.validate_string(secret_name, max_length=512)
            response = self.secrets_manager.get_secret_value(SecretId=validated_name)
            
            if 'SecretString' in response:
                return json.loads(response['SecretString'])
            else:
                raise ValueError("Secret not in expected format")
        except ClientError as e:
            logger.error(f"Error retrieving secret: {e.response['Error']['Code']}")
            raise
    
    def put_s3_object(self, bucket: str, key: str, data: bytes) -> None:
        """Securely upload to S3 with validation"""
        validated_bucket = InputValidator.validate_bucket_name(bucket)
        validated_key = InputValidator.validate_string(key, max_length=1024, pattern=r'^[a-zA-Z0-9/_.-]+$')
        
        try:
            self.s3.put_object(
                Bucket=validated_bucket,
                Key=validated_key,
                Body=data,
                ServerSideEncryption='aws:kms'
            )
        except ClientError as e:
            logger.error(f"S3 upload error: {e.response['Error']['Code']}")
            raise
    
    def get_s3_object(self, bucket: str, key: str) -> bytes:
        """Securely retrieve from S3 with validation"""
        validated_bucket = InputValidator.validate_bucket_name(bucket)
        validated_key = InputValidator.validate_string(key, max_length=1024, pattern=r'^[a-zA-Z0-9/_.-]+$')
        
        try:
            response = self.s3.get_object(Bucket=validated_bucket, Key=validated_key)
            return response['Body'].read()
        except ClientError as e:
            logger.error(f"S3 download error: {e.response['Error']['Code']}")
            raise
    
    def put_dynamodb_item(self, table_name: str, item: Dict[str, Any]) -> None:
        """Securely write to DynamoDB with validation"""
        validated_table = InputValidator.validate_table_name(table_name)
        
        try:
            table = self.dynamodb.Table(validated_table)
            table.put_item(Item=self._convert_floats_to_decimal(item))
        except ClientError as e:
            logger.error(f"DynamoDB write error: {e.response['Error']['Code']}")
            raise
    
    def get_dynamodb_item(self, table_name: str, key: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        """Securely read from DynamoDB with validation"""
        validated_table = InputValidator.validate_table_name(table_name)
        
        try:
            table = self.dynamodb.Table(validated_table)
            response = table.get_item(Key=key)
            return response.get('Item')
        except ClientError as e:
            logger.error(f"DynamoDB read error: {e.response['Error']['Code']}")
            raise
    
    def publish_sns(self, topic_arn: str, message: str, subject: str = None) -> None:
        """Securely publish to SNS with validation"""
        if topic_arn not in ALLOWED_TOPIC_ARNS:
            raise ValueError("Invalid topic ARN")
        
        validated_message = InputValidator.validate_string(message, max_length=262144)
        
        try:
            params = {
                'TopicArn': topic_arn,
                'Message': validated_message
            }
            if subject:
                params['Subject'] = InputValidator.validate_string(subject, max_length=100)
            
            self.sns.publish(**params)
        except ClientError as e:
            logger.error(f"SNS publish error: {e.response['Error']['Code']}")
            raise
    
    def send_sqs_message(self, queue_url: str, message_body: str, attributes: Dict[str, Any] = None) -> None:
        """Securely send SQS message with validation"""
        validated_message = InputValidator.validate_string(message_body, max_length=262144)
        
        try:
            params = {
                'QueueUrl': queue_url,
                'MessageBody': validated_message
            }
            if attributes:
                params['MessageAttributes'] = attributes
            
            self.sqs.send_message(**params)
        except ClientError as e:
            logger.error(f"SQS send error: {e.response['Error']['Code']}")
            raise
    
    @staticmethod
    def _convert_floats_to_decimal(obj: Any) -> Any:
        """Convert floats to Decimal for DynamoDB compatibility"""
        if isinstance(obj, float):
            return Decimal(str(obj))
        elif isinstance(obj, dict):
            return {k: SecureAWSClients._convert_floats_to_decimal(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [SecureAWSClients._convert_floats_to_decimal(item) for item in obj]
        return obj


def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    """
    Secure Lambda handler with input validation and error handling
    """
    try:
        # Sanitize event data for logging
        sanitized_event = InputValidator.sanitize_log_data(event)
        logger.info(f"Processing event: {json.dumps(sanitized_event)}")
        
        # Initialize secure AWS clients
        aws_clients = SecureAWSClients()
        
        # Validate required fields
        if 'body' in event:
            if isinstance(event['body'], str):
                body = json.loads(event['body'])
            else:
                body = event['body']
        else:
            body = event
        
        # Example: Process data securely
        action = body.get('action')
        
        if action == 'store_data':
            # Validate and sanitize input
            data = InputValidator.validate_string(body.get('data', ''), max_length=10000)
            table_name = body.get('table_name')
            
            # Store in DynamoDB
            item = {
                'id': InputValidator.validate_string(body.get('id', ''), pattern=r'^[a-zA-Z0-9-]+$'),
                'data': data,
                'timestamp': int(context.request_id) if hasattr(context, 'request_id') else 0
            }
            
            aws_clients.put_dynamodb_item(table_name, item)
            
            return {
                'statusCode': 200,
                'headers': {
                    'Content-Type': 'application/json',
                    'X-Content-Type-Options': 'nosniff',
                    'Strict-Transport-Security': 'max-age=31536000; includeSubDomains'
                },
                'body': json.dumps({'message': 'Data stored successfully'})
            }
        
        elif action == 'retrieve_data':
            # Validate input
            item_id = InputValidator.validate_string(body.get('id', ''), pattern=r'^[a-zA-Z0-9-]+$')
            table_name = body.get('table_name')
            
            # Retrieve from DynamoDB
            item = aws_clients.get_dynamodb_item(table_name, {'id': item_id})
            
            if item:
                # Sanitize output
                sanitized_item = InputValidator.sanitize_log_data(item)
                return {
                    'statusCode': 200,
                    'headers': {
                        'Content-Type': 'application/json',
                        'X-Content-Type-Options': 'nosniff'
                    },
                    'body': json.dumps(sanitized_item)
                }
            else:
                return {
                    'statusCode': 404,
                    'headers': {'Content-Type': 'application/json'},
                    'body': json.dumps({'error': 'Item not found'})
                }
        
        else:
            return {
                'statusCode': 400,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({'error': 'Invalid action'})
            }
    
    except ValueError as e:
        logger.error(f"Validation error: {str(e)}")
        return {
            'statusCode': 400,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'error': 'Invalid input'})
        }
    
    except ClientError as e:
        logger.error(f"AWS service error: {e.response['Error']['Code']}")
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'error': 'Internal server error'})
        }
    
    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}")
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'error': 'Internal server error'})
        }